import torch
import torch.nn as nn

class FFN(nn.Module):
    def __init__(self, dim, expanded_dim=None):
        super().__init__()
        if expanded_dim is None:
            expanded_dim = 4 * dim
        self.w1 = nn.Linear(dim, expanded_dim)
        self.act = nn.ReLU()
        self.w2 = nn.Linear(expanded_dim, dim)

    def forward(self, x):
        return self.w2(self.act(self.w1(x)))

x = torch.randn(1, 8)
ffn = FFN(dim=8)
print("FFN output shape:", ffn(x).shape)
print("Parameter count:", sum(p.numel() for p in ffn.parameters()))
